const FILTERS = [
  { key: 'all', label: 'All' },
  { key: 'family', label: 'Family' },
  { key: 'couples', label: 'Couples' },
  { key: 'newborn', label: 'Newborn' },
]

const GalleryPage = ({ data }) => {
  const [activeFilter, setActiveFilter] = useState('all')

  const sorted = [...data.allFile.edges].sort((a, b) => {
    const scoreA = (photoMeta[a.node.base] || {}).overall || 0
    const scoreB = (photoMeta[b.node.base] || {}).overall || 0
    return scoreB - scoreA
  })

  const displayed =
    activeFilter === 'all'
      ? sorted
      : sorted.filter(({ node }) => {
          const meta = photoMeta[node.base]
          return meta && meta.categories.includes(activeFilter)
        })

  return (
    <>
      <Helmet>
        <title>Photography | Carson Covell</title>
        <meta
          name="description"
          content="Photography by Carson Covell — family, couples, and newborn portraits in the Colorado mountains."
        />
        <meta name="twitter:card" content="summary" />
        <meta name="twitter:site" content="@carsoncovell" />
        <link
          rel="shortcut icon"
          href="./favicon/favicon.ico"
          type="image/x-icon"
        />
      </Helmet>

      <Navigation />

      <main className={galleryPage}>
        <div className={header}>
          <h1>Photography</h1>
          <p>Family, couples, and newborn portraits.</p>
        </div>

        <div className={filterRow}>
          {FILTERS.map(({ key, label }) => (
            <button
              key={key}
              className={`${filterBtn}${activeFilter === key ? ` ${filterBtnActive}` : ''}`}
              onClick={() => setActiveFilter(key)}
            >
              {label}
            </button>
          ))}
        </div>

        <div className={masonryGrid}>
          {displayed.length === 0 && (
            <p className={emptyState}>No photos in this category yet.</p>
          )}
          {displayed.map(({ node }) => (
            <div key={node.id} className={photoItem}>
              <Img
                fluid={node.childImageSharp.fluid}
                alt="Photography by Carson Covell"
              />
            </div>
          ))}
        </div>
      </main>

      <Footer />
    </>
  )
}

export default GalleryPage

export const query = graphql`
  query GalleryQuery {
    allFile(
      filter: {
        sourceInstanceName: { eq: "img" }
        relativeDirectory: { eq: "gallery" }
      }
    ) {
      edges {
        node {
          id
          base
          childImageSharp {
            fluid(maxWidth: 800, quality: 85) {
              ...GatsbyImageSharpFluid_withWebp
            }
          }
        }
      }
    }
  }
`
